import spoon.reflect.visitor.filter.TypeFilter;

public class Main {
    public static void main(String[] args) {
        // Create a Spoon launcher for processing Java files
        Launcher launcher = new Launcher();
        launcher.getEnvironment().setAutoImports(true);
        launcher.getEnvironment().setComplianceLevel(8);

        // Add the source directory to process
        launcher.addInputResource("/workspace/JRedisGraph/src/main/java");
        launcher.addInputResource("/workspace/JRedisGraph/src/test/java");

        // Process the files
        launcher.buildModel();

        Factory factory = launcher.getFactory();

        // Create the transformation rule
        processPipelineInterfaces(factory);

        // Write the modified code back
        launcher.setSourceOutputDirectory("/workspace/JRedisGraph/src/main/java");
        launcher.setBinaryOutputDirectory("/workspace/JRedisGraph/target/classes");
        launcher.export();

        System.out.println("Transformation completed successfully");
    }

    private static void processPipelineInterfaces(Factory factory) {
        // Find all files that have imports from redis.clients.jedis.commands
        List<CtImport> imports = factory.getModel().getElements(new TypeFilter<>(CtImport.class));

        // Remove imports for the old pipeline interfaces
        List<String> oldPipelineInterfaces = Arrays.asList(
            "redis.clients.jedis.commands.BasicRedisPipeline",
            "redis.clients.jedis.commands.BinaryRedisPipeline",
            "redis.clients.jedis.commands.BinaryScriptingCommandsPipeline",
            "redis.clients.jedis.commands.ClusterPipeline",
            "redis.clients.jedis.commands.MultiKeyBinaryRedisPipeline",
            "redis.clients.jedis.commands.MultiKeyCommandsPipeline",
            "redis.clients.jedis.commands.RedisPipeline",
            "redis.clients.jedis.commands.ScriptingCommandsPipeline"
        );

        for (CtImport imp : imports) {
            String importedType = imp.getReference().getQualifiedName();
            if (oldPipelineInterfaces.contains(importedType)) {
                // Remove the import
                imp.delete();
            }
        }

        // Find all interfaces that extend the old pipeline interfaces
        List<CtInterface> interfaces = factory.getModel().getElements(new TypeFilter<>(CtInterface.class));

        for (CtInterface intf : interfaces) {
            // Check if this interface extends any of the old pipeline interfaces
            List<CtTypeReference<?>> superInterfaces = intf.getSuperInterfaces();
            List<CtTypeReference<?>> newSuperInterfaces = new ArrayList<>();

            for (CtTypeReference<?> superInterface : superInterfaces) {
                String superInterfaceName = superInterface.getQualifiedName();

                // Map old interfaces to new ones
                if ("redis.clients.jedis.commands.BasicRedisPipeline".equals(superInterfaceName)) {
                    // Replace with Pipeline
                    newSuperInterfaces.add(intf.getFactory().Type().createReference("redis.clients.jedis.Pipeline"));
                } else if ("redis.clients.jedis.commands.BinaryRedisPipeline".equals(superInterfaceName)) {
                    // Replace with Pipeline
                    newSuperInterfaces.add(intf.getFactory().Type().createReference("redis.clients.jedis.Pipeline"));
                } else if ("redis.clients.jedis.commands.BinaryScriptingCommandsPipeline".equals(superInterfaceName)) {
                    // Replace with ScriptingPipeline
                    newSuperInterfaces.add(intf.getFactory().Type().createReference("redis.clients.jedis.ScriptingPipeline"));
                } else if ("redis.clients.jedis.commands.ClusterPipeline".equals(superInterfaceName)) {
                    // Replace with ClusterPipeline
                    newSuperInterfaces.add(intf.getFactory().Type().createReference("redis.clients.jedis.ClusterPipeline"));
                } else if ("redis.clients.jedis.commands.MultiKeyBinaryRedisPipeline".equals(superInterfaceName)) {
                    // Replace with MultiKeyPipeline
                    newSuperInterfaces.add(intf.getFactory().Type().createReference("redis.clients.jedis.MultiKeyPipeline"));
                } else if ("redis.clients.jedis.commands.MultiKeyCommandsPipeline".equals(superInterfaceName)) {
                    // Replace with MultiKeyPipeline
                    newSuperInterfaces.add(intf.getFactory().Type().createReference("redis.clients.jedis.MultiKeyPipeline"));
                } else if ("redis.clients.jedis.commands.RedisPipeline".equals(superInterfaceName)) {
                    // Replace with Pipeline
                    newSuperInterfaces.add(intf.getFactory().Type().createReference("redis.clients.jedis.Pipeline"));
                } else if ("redis.clients.jedis.commands.ScriptingCommandsPipeline".equals(superInterfaceName)) {
                    // Replace with ScriptingPipeline
                    newSuperInterfaces.add(intf.getFactory().Type().createReference("redis.clients.jedis.ScriptingPipeline"));
                } else {
                    newSuperInterfaces.add(superInterface);
                }
            }

            // Update the super interfaces
            intf.setSuperInterfaces(newSuperInterfaces);
        }

        // Also handle the RedisGraphPipeline and RedisGraphTransaction classes
        List<CtClass> classes = factory.getModel().getElements(new TypeFilter<>(CtClass.class));

        for (CtClass cls : classes) {
            // Check if this class extends the old Transaction class that has the client parameter issue
            if (cls.getSuperclass() != null) {
                String superClass = cls.getSuperclass().getQualifiedName();
                if ("redis.clients.jedis.Transaction".equals(superClass)) {
                    // We need to handle the constructor call to make it compatible with Jedis 4.3.2
                    // This is a more complex case that would need additional handling
                }
            }
        }
    }
}

